  --d-control-h: 2.25rem;
  --d-control-text: 0.875rem;
  --d-control-leading: 1.25rem;
  --d-control-px: 0.75rem;
  /* Preset-switchable focus-ring width and card elevation (Approach D). */
  --d-ring-width: 3px;
  --d-surface-shadow: 0 0 #0000;
}

