}

body {
  --d-background: var(--background);
  --d-foreground: var(--foreground);
  --d-card: var(--card);
  --d-popover: var(--popover);
  --d-primary: var(--primary);
  --d-primary-foreground: var(--primary-foreground);
  --d-accent: var(--accent);
  --d-accent-foreground: var(--accent-foreground);
  --d-muted: var(--muted);
  --d-muted-foreground: var(--muted-foreground);
  --d-border: var(--border);
  --d-ring: var(--ring);
  --d-info: var(--primary);
  --d-info-muted: color-mix(in oklch, var(--primary) 10%, var(--background));
  --d-success: var(--chart-2);
  --d-success-muted: color-mix(in oklch, var(--chart-2) 12%, var(--background));
  --d-warning: var(--chart-4);
  --d-warning-muted: color-mix(in oklch, var(--chart-4) 14%, var(--background));
  --d-danger: var(--destructive);
  --d-danger-muted: color-mix(in oklch, var(--destructive) 10%, var(--background));
  /* Text-on-muted variants: status colors pulled towards the foreground so small
     (12px) text on the *-muted tints (and plain background/card) clears the
     WCAG 4.5:1 contrast threshold in light and dark presets alike. The pull
     weight is solved per source hue: success (--chart-2) and warning
     (--chart-4) need 42% — 30% left b6's amber success at 4.10 and every
     preset's dark warning near 3.8 — while info (--primary) and danger
     (--destructive) already clear it at 30%. Verified >=4.9:1 worst case
     across all 15 presets, both schemes. */
  --d-info-text: color-mix(in oklch, var(--d-info), var(--foreground) 30%);
  --d-success-text: color-mix(in oklch, var(--d-success), var(--foreground) 42%);
  --d-warning-text: color-mix(in oklch, var(--d-warning), var(--foreground) 42%);
  --d-danger-text: color-mix(in oklch, var(--d-danger), var(--foreground) 30%);
  /* Same idea for brand-colored text on primary tints (e.g. search-result
     highlights on bg-primary/10): presets whose primary sits near the 4.5:1
     boundary on white drop below it on the tint without the pull. Mixed
     towards an explicitly hue-less black (white in dark mode, see below) —
     mixing towards var(--foreground) would rotate the brand hue, because a
     color specified in oklch keeps its hue in interpolation even at chroma 0
     (only *converted* achromatic colors get the powerless-hue treatment). */
  --d-primary-text: color-mix(in oklch, var(--primary), oklch(0 0 none) 35%);
  /* Brand-colored links sitting inside a same-family or neutral box surface
     (.ce-frame--bg-10/80, accent cards): the raw --primary often lands near the
     3:1 UI floor on those tints, below the 4.5:1 text minimum. Reuse the
     hue-preserving primary-text pull so links stay on-brand and legible; the
     underline carries the non-color affordance. Resolves per preset and per
     scheme via --d-primary-text (dark mode pulls towards white instead). */
  --d-link-on-muted: var(--d-primary-text);
  /* Brand links/text on the default background/card surfaces (.link, the
     text-link utility). Presets whose primary cannot serve as small text
     there (bright amber/lime) override this with a solved darker ink. */
  --d-link: var(--primary);
  /* Ink for text on --foreground-based image scrims (card-overlay, parallax
     heroes): --background is the exact inverse of the scrim color in every
     preset and scheme. NOT --primary-foreground — that is dark in the bright
     amber/lime presets and vanishes on a dark scrim. */
  --d-overlay-foreground: var(--background);
  --d-radius-sm: calc(var(--radius) * 0.6);
  --d-radius-md: calc(var(--radius) * 0.8);
  --d-radius-lg: var(--radius);
  --d-radius-xl: calc(var(--radius) * 1.4);
  --d-radius-full: 9999px;
  --d-spacing-0-5: 0.125rem;
  --d-spacing-1: 0.25rem;
  --d-spacing-2: 0.5rem;
  --d-spacing-3: 0.75rem;
  --d-spacing-4: 1rem;
  --d-spacing-6: 1.5rem;
  --d-spacing-8: 2rem;
  --d-spacing-10: 2.5rem;
  --d-spacing-12: 3rem;
  --d-spacing-16: 4rem;
  --d-spacing-20: 5rem;
  --d-spacing-2xs: 0.25rem;
  --d-spacing-xs: 0.5rem;
  --d-spacing-sm: 0.75rem;
  --d-spacing-md: 1rem;
  --d-spacing-lg: 1.5rem;
  --d-spacing-xl: 2rem;
  --d-spacing-2xl: 3rem;
  --d-spacing-3xl: 4rem;
  --d-text-xs: 0.75rem;
  --d-text-sm: 0.875rem;
  --d-text-base: 1rem;
  --d-text-lg: 1.125rem;
  --d-text-xl: 1.25rem;
  --d-text-2xl: 1.5rem;
  --d-text-3xl: 1.875rem;
  --d-text-4xl: 2.25rem;
  --d-text-5xl: 3rem;
  --d-text-6xl: 3.75rem;
}

/* Dark scheme pulls brand text towards white instead of black. Declared on
   body (not in the html-level .dark block) so the mix resolves against the
   preset's --primary, which the body[data-shadcn-preset] blocks override.
   --d-link and --d-primary-text are re-declared here so a light-mode literal
   from a body[data-shadcn-preset] block (same specificity, earlier in the
   file) never leaks into dark mode; the .dark body[data-shadcn-preset]
   blocks then re-override both where a solved dark value exists. */
.dark body {
  --d-primary-text: color-mix(in oklch, var(--primary), oklch(1 0 none) 35%);
  --d-link: var(--primary);
}

@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";
@import "@fontsource-variable/inter";
@import "@fontsource-variable/geist";
@import "@fontsource-variable/jetbrains-mono";
@import "@fontsource-variable/nunito-sans";

@source "../Components";
@source "../Solr";
@source "../Templates";
@source "../Extensions";
@source "../ShadcnUi";
@source "../FluidStyledContent";
@source "../../Public/Js";
@source "../../../ContentBlocks";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --font-sans: var(--d-font-sans);
  --font-heading: var(--d-font-heading);
  --font-mono: var(--d-font-mono);

  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  /* Brand link ink: --primary, except where a preset overrides --d-link with a
     solved darker/brighter value so small text on background/card holds 4.5:1
     (bright amber/lime primaries). Use text-link instead of text-primary for
     running text and links; keep text-primary for decorative icons/chips. */
  --color-link: var(--d-link, var(--primary));
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);

  --radius-sm: calc(var(--radius) * 0.6);
  --radius-md: calc(var(--radius) * 0.8);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) * 1.4);
  --radius-2xl: calc(var(--radius) * 1.8);
  --radius-3xl: calc(var(--radius) * 2.2);
  --radius-4xl: calc(var(--radius) * 2.6);

  --shadow-2xs: var(--d-shadow-2xs);
  --shadow-xs: var(--d-shadow-xs);
  --shadow-sm: var(--d-shadow-sm);
  --shadow: var(--d-shadow);
  --shadow-md: var(--d-shadow-md);
  --shadow-lg: var(--d-shadow-lg);
  --shadow-xl: var(--d-shadow-xl);
  --shadow-2xl: var(--d-shadow-2xl);

  --tracking-tight: 0em;
}

/* ---------------------------------------------------------------------------
 * Preset-switchable control shape (Approach D).
 * Token VALUES live per preset in shadcn-theme.css (:root + body[data-shadcn-preset]),
 * so switching the shadcn preset re-cascades control height / text / padding at
 * runtime. Corner radius switches via shadcn's own --radius scale (rounded-md /
 * rounded-xl), which every preset already declares.
 * ------------------------------------------------------------------------- */
@utility d-control-h {
  height: var(--d-control-h, 2.25rem);
}

@utility d-control-text {
  font-size: var(--d-control-text, 0.875rem);
  line-height: var(--d-control-leading, 1.25rem);
}

@utility d-control-px {
  padding-inline: var(--d-control-px, 0.75rem);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }

  html {
    @apply font-sans;
  }

  body {
    @apply bg-background text-foreground;
  }
}

@layer components {
  /* Tailwind Styled Content-compatible frame/prose defaults, implemented with Tailwind v4 and shadcn tokens. */
  .frame,
  .ce-frame {
    color: var(--foreground);
  }

  .frame:not(:first-child),
  .ce-frame:not(:first-child) {
    margin-block-start: var(--d-section-y, 3rem);
  }

  /* The page breadcrumb leads the content flow — the element after it is
     still the visual start of the page. */
  .desiderio-breadcrumb + .ce-frame {
    margin-block-start: 0;
  }

  .desiderio-section {
    position: relative;
    isolation: isolate;
    overflow-x: clip;
    border-block-start: 1px solid color-mix(in oklch, var(--border) 72%, transparent);
  }

  .desiderio-section:first-child,
  .desiderio-breadcrumb + .desiderio-section {
    border-block-start: 0;
  }

  .desiderio-section > .desiderio-container {
    container-type: inline-size;
  }

  .desiderio-section :where(.card, .feature-card, .pricing-card, .testimonial-card, .metric-card, .stat-card, .team-card, .case-study-card, .resource-card, .product-card, .job-card, .leaderboard__item, .notification, .alert, .table-wrapper, [class$="__card"], [class*="__card "], [class$="__panel"], [class*="__panel "]) {
    border-color: color-mix(in oklch, var(--border) 82%, transparent);
    background-color: color-mix(in oklch, var(--card) 96%, var(--background));
    box-shadow: var(--shadow-sm);
  }

  .desiderio-section :where(.card, .feature-card, .pricing-card, .testimonial-card, .metric-card, .stat-card, .team-card, .case-study-card, .resource-card, .product-card, .job-card, .leaderboard__item, .notification, .alert, .table-wrapper, [class$="__card"], [class*="__card "], [class$="__panel"], [class*="__panel "]) :where(.btn, button, a) {
    max-width: 100%;
  }

  .desiderio-section :where(.badge, [class$="__badge"], [class*="__badge "]) {
    letter-spacing: 0;
    white-space: normal;
  }

  .desiderio-section :where(img, video, iframe) {
    border: 1px solid color-mix(in oklch, var(--border) 72%, transparent);
    background-color: var(--muted);
    box-shadow: var(--shadow-sm);
  }

  .desiderio-section :where(.btn, button, input, textarea, select) {
    min-width: 0;
  }

  .desiderio-section :where(.btn, button) {
    text-wrap: balance;
  }

  .desiderio-section :where(h1, h2, h3) {
    text-wrap: balance;
  }

  .desiderio-section :where(p, li) {
    overflow-wrap: anywhere;
  }

  @media (max-width: 767px) {
    .desiderio-section {
      padding-block: 2.25rem;
    }

    .desiderio-section > .desiderio-container {
      padding-inline: 1rem;
    }

    .desiderio-section :where(.btn, button, input, textarea, select) {
      max-width: 100%;
    }
  }

  .frame :where(h1, h2, h3, h4, h5, h6),
  .ce-frame :where(h1, h2, h3, h4, h5, h6),
  .ce-bodytext :where(h1, h2, h3, h4, h5, h6),
  .prose :where(h1, h2, h3, h4, h5, h6):not(:where(.desiderio-section *, .not-prose, .not-prose *)) {
    color: var(--foreground);
    font-family: var(--font-heading);
    font-weight: 600;
    letter-spacing: 0;
  }

  .frame :where(p, li, figcaption),
  .ce-frame :where(p, li, figcaption),
  .ce-bodytext :where(p, li, figcaption),
  .prose :where(p, li, figcaption):not(:where(.desiderio-section *, .not-prose, .not-prose *)) {
    color: var(--muted-foreground);
    line-height: 1.7;
  }

  /* Anchor styling is for running text only — shadcn buttons render as <a>
     too and must keep their own contract (no underline, no color repaint).
     .not-prose is the generic escape hatch for embedded UI. */
  .frame :where(a:not([data-slot='button'], .not-prose, .not-prose *)),
  .ce-frame :where(a:not([data-slot='button'], .not-prose, .not-prose *)),
  .ce-bodytext :where(a:not([data-slot='button'], .not-prose, .not-prose *)),
  .prose :where(a:not([data-slot='button'])):not(:where(.desiderio-section *, .not-prose, .not-prose *)) {
    /* --d-link, not raw --primary: presets with a bright accent (amber/lime)
       override it with a solved ink so small link text holds 4.5:1. */
    color: var(--d-link, var(--primary));
    text-decoration-line: underline;
    text-underline-offset: 0.25rem;
  }

  .frame :where(a:hover:not([data-slot='button'], .not-prose, .not-prose *)),
  .ce-frame :where(a:hover:not([data-slot='button'], .not-prose, .not-prose *)),
  .ce-bodytext :where(a:hover:not([data-slot='button'], .not-prose, .not-prose *)),
  .prose :where(a:hover:not([data-slot='button'])):not(:where(.desiderio-section *, .not-prose, .not-prose *)) {
    /* Not a mix towards var(--foreground): its oklch hue 0 would rotate the
       brand hue. --d-primary-text is the hue-safe, scheme-aware pull. */
    color: var(--d-primary-text, var(--primary));
  }

  .frame :where(img, video, iframe),
  .ce-frame :where(img, video, iframe),
  .prose :where(img, video, iframe):not(:where(.desiderio-section *, .not-prose, .not-prose *)) {
    display: block;
    max-width: 100%;
    height: auto;
    border-radius: var(--radius-lg);
  }

  .frame :where(blockquote),
  .ce-frame :where(blockquote),
  .prose :where(blockquote):not(:where(.desiderio-section *, .not-prose, .not-prose *)) {
    border-inline-start: 2px solid var(--border);
    color: var(--foreground);
    padding-inline-start: 1rem;
  }

  .frame :where(table),
  .ce-frame :where(table),
  .prose :where(table):not(:where(.desiderio-section *, .not-prose, .not-prose *)) {
    width: 100%;
    caption-side: bottom;
    border-collapse: collapse;
    font-size: 0.875rem;
  }

  .frame :where(th),
  .ce-frame :where(th),
  .prose :where(th):not(:where(.desiderio-section *, .not-prose, .not-prose *)) {
    color: var(--foreground);
    font-weight: 500;
    text-align: start;
  }

  .frame :where(th, td),
  .ce-frame :where(th, td),
  .prose :where(th, td):not(:where(.desiderio-section *, .not-prose, .not-prose *)) {
    border-block-end: 1px solid var(--border);
    padding: 0.5rem;
  }

  .frame :where(input:not(.d-shadcn-control), textarea:not(.d-shadcn-control), select:not(.d-shadcn-control)),
  .ce-frame :where(input:not(.d-shadcn-control), textarea:not(.d-shadcn-control), select:not(.d-shadcn-control)),
  .desiderio-content-element :where(input:not(.d-shadcn-control), textarea:not(.d-shadcn-control), select:not(.d-shadcn-control)) {
    min-height: 2rem;
    border-radius: var(--radius-lg);
    border: 1px solid var(--input);
    background: transparent;
    color: var(--foreground);
    font-size: 0.875rem;
  }

  .frame :where(button:not(.d-shadcn-control), a, input:not(.d-shadcn-control), textarea:not(.d-shadcn-control), select:not(.d-shadcn-control)):focus-visible,
  .ce-frame :where(button:not(.d-shadcn-control), a, input:not(.d-shadcn-control), textarea:not(.d-shadcn-control), select:not(.d-shadcn-control)):focus-visible,
  .desiderio-content-element :where(button:not(.d-shadcn-control), a, input:not(.d-shadcn-control), textarea:not(.d-shadcn-control), select:not(.d-shadcn-control)):focus-visible {
    border-color: var(--ring);
    outline: none;
    box-shadow: 0 0 0 3px color-mix(in oklch, var(--ring) 50%, transparent);
  }

  .results-highlight {
    @apply inline box-decoration-clone rounded-md bg-primary/10 px-1 py-0.5 font-medium ring-1 ring-primary/20;
    /* Not text-primary: 14px text on the primary tint needs the contrast-safe
       mix (see --d-primary-text in shadcn-theme.css). */
    color: var(--d-primary-text, var(--primary));
  }

  .dark .results-highlight {
    @apply bg-primary/20 ring-primary/30;
  }

  .facet-option-list :where(a),
  #tx-solr-frequent-searches :where(a),
  #tx-solr-lastsearches :where(a),
  #tx-solr-sorting :where(a, summary),
  .solr-pagination :where(a),
  #tx-solr-facets-in-use :where(a),
  .facet-option-list :where(a:hover, a:focus, a:focus-visible, a:active),
  #tx-solr-frequent-searches :where(a:hover, a:focus, a:focus-visible, a:active),
  #tx-solr-lastsearches :where(a:hover, a:focus, a:focus-visible, a:active),
  #tx-solr-sorting :where(a:hover, a:focus, a:focus-visible, a:active, summary:hover, summary:focus, summary:focus-visible, summary:active),
  .solr-pagination :where(a:hover, a:focus, a:focus-visible, a:active),
  #tx-solr-facets-in-use :where(a:hover, a:focus, a:focus-visible, a:active) {
    text-decoration-line: none;
  }
}

/* Unlayered on purpose: the container's px-4 utility would win against any
   @layer rule. Content elements rendered inside an article body already sit
   in the page container — their own container padding would double-indent
   the copy against the article header. Start stays flush with the post
   title; the end side keeps breathing room toward the sidebar. Painted
   bands (cta-banner and content-highlight variants) get the full inline
   padding back so copy never touches the band edge. */
.prose :where(.desiderio-section > .desiderio-container) {
  padding-inline: 0 2rem;
}
.prose :where(
  .cta-banner--primary, .cta-banner--muted, .cta-banner--dark,
  .content-highlight--primary, .content-highlight--muted, .content-highlight--bordered
) > .desiderio-container {
  padding-inline: var(--d-spacing-2xl, 3rem);
}
